sys_script_include.script:
var RecruitmentRequestUtils = Class.create();
RecruitmentRequestUtils.prototype = {
    initialize: function() {},
    /**
     * Updates the 'u_time_of_ticket' field for all recruitment requests.
     * Calculation: Today - Start Date
     */
    updateTicketAging: function() {
        var grRecruitRequest = new GlideRecord('x_1763182_talent_0_recruitment_request');
        grRecruitRequest.query();

        while (grRecruitRequest.next()) {
            if (!grRecruitRequest.u_start_date.nil()) {
                var today = new GlideDateTime();
                var startDate = new GlideDateTime(grRecruitRequest.u_start_date);

                var duration = GlideDateTime.subtract(startDate, today);
                grRecruitRequest.u_time_of_ticket = duration.getDayPart();
                grRecruitRequest.update();
            }
        }
    },
    type: 'RecruitmentRequestUtils'
};
